#!/bin/bash
#
# Automated release script for stolostron/gatekeeper
# Based on the manual process in docs/README.md
#
# Usage: ./build/create-release.sh [OPTIONS]
#
# Options:
#   --dry-run          Show what would be done without executing
#   --resume-from N    Resume from phase N (1-5)
#   --help            Show this help message
#
# Example: ./build/create-release.sh --dry-run
#
# AI-generated by Claude Code (claude.ai/code) based on the manual process in docs/README.md
#

set -euo pipefail

# Script configuration
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
PROJECT_ROOT="$(cd "${SCRIPT_DIR}/.." && pwd)"
TEMP_DIR=$(mktemp -d)
LOG_FILE="${TEMP_DIR}/release.log"

# Default values
DRY_RUN=false
RESUME_FROM=1
VERBOSE=false

# Color codes for output
RED='\033[0;31m'
GREEN='\033[0;32m'
YELLOW='\033[1;33m'
BLUE='\033[0;34m'
NC='\033[0m' # No Color

# Cleanup function
cleanup() {
    local exit_code=$?
    if [[ ${exit_code} -ne 0 ]]; then
        echo -e "${RED}Script failed. Check log at: ${LOG_FILE}${NC}"
        echo -e "${YELLOW}To resume the script after fixing any issues, use: --resume-from ${RESUME_FROM}${NC}"
        echo -e "${YELLOW}To cleanup local changes, you may need to run:${NC}"
        echo "  git checkout main"
        echo "  git branch -D release-\${NEW_RELEASE} patch-release-\${NEW_RELEASE} 2>/dev/null || true"
        echo "  git tag -d v\${NEW_RELEASE_VERSION} 2>/dev/null || true"
    fi
    # Don't remove temp dir if we failed - user might want to check logs
}

trap cleanup EXIT

# Logging function
log() {
    echo "[$(date '+%Y-%m-%d %H:%M:%S')] $*" | tee -a "${LOG_FILE}"
}

error() {
    echo -e "${RED}ERROR: $*${NC}" >&2
    exit 1
}

warning() {
    echo -e "${YELLOW}WARNING: $*${NC}" >&2
}

info() {
    echo -e "${BLUE}INFO: $*${NC}"
}

success() {
    echo -e "${GREEN}SUCCESS: $*${NC}"
}

# Help function
show_help() {
    cat <<EOF
Automated release script for stolostron/gatekeeper

This script automates the 8-step manual release process documented in docs/README.md.
It automatically detects the latest upstream tag and previous stolostron release.

Usage: ${0} [OPTIONS]

Options:
  --dry-run             Show what would be done without executing commands
  --resume-from PHASE   Resume from specified phase (1-5):
                          1: Create initial release branch
                          2: Create and rebase patch branch  
                          3: Interactive commit squashing
                          4: Push patch branch and create PR
                          5: Tag and push final release
  --verbose            Enable verbose output
  --help               Show this help message

Examples:
  ${0}                                 # Normal release (auto-detects versions)
  ${0} --dry-run                       # Show what would happen
  ${0} --resume-from 3                 # Resume from phase 3

What this script does:
  - Automatically fetches the latest tag from open-policy-agent/gatekeeper
  - Automatically detects the latest release branch from stolostron/gatekeeper
  - Executes the same 5-phase release process as the manual workflow

Prerequisites:
  - Git repository with stolostron and open-policy-agent remotes
  - gh CLI tool installed and authenticated
  - gsed (on macOS) or sed (on Linux)
  - Clean working directory

EOF
}

# Parse command line arguments
parse_args() {
    while [[ $# -gt 0 ]]; do
        case $1 in
        --dry-run)
            DRY_RUN=true
            shift
            ;;
        --resume-from)
            RESUME_FROM="${2}"
            if [[ ! "${RESUME_FROM}" =~ ^[1-5]$ ]]; then
                error "Invalid phase number: ${RESUME_FROM}. Must be 1-5."
            fi
            shift 2
            ;;
        --verbose)
            VERBOSE=true
            shift
            ;;
        --help)
            show_help
            exit 0
            ;;
        -*)
            error "Unknown option: ${1}"
            ;;
        *)
            error "Unexpected argument: ${1}. Use --help for usage information."
            ;;
        esac
    done
}

# Execute command with optional dry-run
execute() {
    local cmd="$*"
    if [[ "${VERBOSE}" == "true" ]] || [[ "${DRY_RUN}" == "true" ]]; then
        log "Would execute: ${cmd}"
    fi

    if [[ "${DRY_RUN}" == "false" ]]; then
        log "Executing: ${cmd}"
        eval "${cmd}" 2>&1 | tee -a "${LOG_FILE}"
        return "${PIPESTATUS[0]}"
    fi
}

# Check prerequisites
check_prerequisites() {
    log "Checking prerequisites..."

    # Check if we're in a git repository
    if ! git rev-parse --git-dir &>/dev/null; then
        error "Not in a git repository"
    fi

    # Check for clean working directory
    if [[ -n "$(git status --porcelain)" ]]; then
        error "Working directory is not clean. Please commit or stash changes."
    fi

    # Check required tools
    local tools=("git" "gh")
    for tool in "${tools[@]}"; do
        if ! command -v "${tool}" >/dev/null; then
            error "Required tool not found: ${tool}"
        fi
    done

    # Check for sed/gsed
    if [[ "$(uname -s | tr '[:upper:]' '[:lower:]')" == "darwin" ]]; then
        if ! command -v gsed >/dev/null; then
            error "gsed not found. Install with: brew install gnu-sed"
        fi
        SED="gsed"
    else
        SED="sed"
    fi

    # Check gh authentication
    if ! execute "gh auth status" &>/dev/null; then
        error "gh CLI not authenticated. Run 'gh auth login' first."
    fi

    success "All prerequisites satisfied"
}

# Detect git remotes
detect_remotes() {
    log "Detecting git remotes..."

    UPSTREAM=$(git remote -v | grep push | awk '/open-policy-agent/ {print $1}' | head -1)
    STOLOSTRON=$(git remote -v | grep push | awk '/stolostron/ {print $1}' | head -1)

    if [[ -z "${UPSTREAM}" ]]; then
        error "No open-policy-agent remote found. Please add it with: git remote add upstream https://github.com/open-policy-agent/gatekeeper.git"
    fi

    if [[ -z "${STOLOSTRON}" ]]; then
        error "No stolostron remote found. Please add it with: git remote add origin https://github.com/stolostron/gatekeeper.git"
    fi

    log "Using upstream remote: ${UPSTREAM}"
    log "Using stolostron remote: ${STOLOSTRON}"

    # Try to detect development fork
    FORK=$(git remote -v | grep push | awk "!/(stolostron|open-policy-agent)/ {print \$1}" | head -1)
    if [[ -n "${FORK}" ]]; then
        log "Detected development fork: ${FORK}"
    else
        error "No development fork detected. You'll need to add a fork remote to continue."
    fi
}

# Fetch latest tag from open-policy-agent/gatekeeper
get_latest_upstream_tag() {
    log "Fetching latest tag from open-policy-agent/gatekeeper..."

    # Fetch tags from upstream, ignoring conflicts with existing local tags
    execute "git fetch --tags ${UPSTREAM}" >/dev/null 2>&1 || true

    # Get the latest semantic version tag (vX.Y.Z only, no beta/alpha/rc)
    local latest_tag
    latest_tag=$(git tag --sort=-version:refname | grep -E '^v[0-9]+\.[0-9]+\.[0-9]+$' | head -1)

    if [[ -z "${latest_tag}" ]]; then
        error "No version tags found in upstream repository"
    fi

    # Remove 'v' prefix to get version number
    NEW_RELEASE_VERSION="${latest_tag#v}"

    log "Latest upstream tag: ${latest_tag}"
    log "New release version: ${NEW_RELEASE_VERSION}"
}

# Get latest release branch from stolostron/gatekeeper
get_latest_stolostron_release() {
    log "Fetching latest release branch from stolostron/gatekeeper..."

    # Fetch branches from stolostron
    if ! execute "git fetch ${STOLOSTRON}" &>/dev/null; then
        error "Failed to fetch branches from stolostron remote: ${STOLOSTRON}"
    fi

    # Get all release-* branches and find the latest version
    local release_branches
    release_branches=$(git branch -r | grep "${STOLOSTRON}/release-" | sed "s|.*${STOLOSTRON}/release-||" | grep -E '^[0-9]+\.[0-9]+$' | sort -V)

    if [[ -z "${release_branches}" ]]; then
        error "No release branches found in stolostron repository"
    fi

    # Get the latest release branch, excluding the new release version
    PREV_RELEASE=$(echo "${release_branches}" | grep -v "${NEW_RELEASE_VERSION%.*}" | tail -1)

    log "Latest stolostron release branch: release-${PREV_RELEASE}"
}

# Generate derived variables
setup_variables() {
    TAG="v${NEW_RELEASE_VERSION}"
    NEW_RELEASE="${NEW_RELEASE_VERSION%.*}"

    log "Configuration:"
    log "Versions:"
    log "  NEW_RELEASE_VERSION: ${NEW_RELEASE_VERSION}"
    log "  PREV_RELEASE: ${PREV_RELEASE}"
    log "  TAG: ${TAG}"
    log "  NEW_RELEASE: ${NEW_RELEASE}"
    log "Remotes:"
    log "  UPSTREAM: ${UPSTREAM}"
    log "  STOLOSTRON: ${STOLOSTRON}"
    log "  FORK: ${FORK}"
    log "Tools:"
    log "  SED: ${SED}"
}

# Confirmation prompt
confirm() {
    local message="${1}"
    if [[ "${DRY_RUN}" == "true" ]]; then
        log "Would prompt: ${message}"
        return 0
    fi

    echo -e "${YELLOW}${message}${NC}"
    read -p "Continue? [y/N] " -n 1 -r
    echo
    if [[ ! ${REPLY} =~ ^[Yy]$ ]]; then
        log "Operation cancelled by user"
        exit 0
    fi
}

# Phase 1: Create initial release branch from upstream
phase1_create_release_branch() {
    log "=== Phase 1: Create initial release branch from upstream ==="

    confirm "This will delete local tag ${TAG} and branch release-${NEW_RELEASE} if they exist, then create a new release branch."

    # Delete existing tag and branch if they exist
    execute "git tag --delete ${TAG} 2>/dev/null || true"
    execute "git branch -D release-${NEW_RELEASE} 2>/dev/null || true"

    # Fetch the upstream release tag
    execute "git fetch ${UPSTREAM} refs/tags/${TAG}:refs/tags/${TAG}"

    # Create and checkout new release branch
    execute "git checkout -b release-${NEW_RELEASE} ${TAG}"

    # Push to stolostron
    execute "git push ${STOLOSTRON} release-${NEW_RELEASE}"

    success "Phase 1 completed: Created release-${NEW_RELEASE} branch"

    info "Please check the Actions tab at https://github.com/stolostron/gatekeeper/actions"
    info "Look for any new workflows that might need to be disabled."
    confirm "Have you checked the Actions tab and disabled any problematic workflows?"
}

# Phase 2: Create and rebase patch branch with customizations
phase2_create_patch_branch() {
    log "=== Phase 2: Create and rebase patch branch with customizations ==="

    confirm "This will create a new patch-release-${NEW_RELEASE} branch and rebase stolostron customizations onto the new release."

    # Delete existing patch branch if it exists
    if [[ -n "$(git branch --list patch-release-${NEW_RELEASE})" ]]; then
        echo -e "${YELLOW}Patch branch patch-release-${NEW_RELEASE} already exists.${NC}"
        read -p "Delete it? [y to delete, N to continue] " -n 1 -r
        if [[ ${REPLY} =~ ^[Yy]$ ]]; then
            execute "git branch -D patch-release-${NEW_RELEASE} 2>/dev/null || true"
        else
            log "Not deleting patch branch patch-release-${NEW_RELEASE}"
        fi
    fi

    # Fetch previous release branch
    execute "git fetch ${STOLOSTRON} release-${PREV_RELEASE}"

    # Checkout previous release and create patch branch
    execute "git checkout ${STOLOSTRON}/release-${PREV_RELEASE}"
    execute "git checkout -b patch-release-${NEW_RELEASE} || git checkout patch-release-${NEW_RELEASE}"

    # Rebase onto new tag, accepting upstream changes in conflicts
    log "Rebasing with strategy 'ours' (accept upstream changes in conflicts)..."
    execute "git rebase -X ours ${TAG}"

    # Apply stolostron customizations
    log "Applying stolostron customizations..."

    # Update manager.yaml
    if [[ -f "config/manager/manager.yaml" ]]; then
        execute "${SED} -i \"s%\\(image: \\)openpolicyagent/gatekeeper:%\\1quay.io/gatekeeper/gatekeeper:%\" config/manager/manager.yaml"
    else
        error "config/manager/manager.yaml not found"
    fi

    # Update Dockerfile.rhtap
    if [[ -f "build/Dockerfile.rhtap" ]]; then
        execute "git checkout ${STOLOSTRON}/release-${PREV_RELEASE} -- build/Dockerfile.rhtap"
        execute "${SED} -i \"s%version.Version=v[^\\\"\\]\\+%version.Version=v${NEW_RELEASE_VERSION}%\" build/Dockerfile.rhtap"
        execute "${SED} -i 's/^\(LABEL version=\).*/\1v${NEW_RELEASE_VERSION}/' build/Dockerfile.rhtap"
    else
        error "build/Dockerfile.rhtap not found"
    fi

    # Regenerate manifests
    execute "make -f Makefile.stolostron manifests"

    # Add all changes and commit
    execute "git add ."
    execute "git commit -m \"!!!squash!!! stolostron updates\" -m \"Update manager.yaml and Dockerfile.rhtap to ${NEW_RELEASE_VERSION}\""

    success "Phase 2 completed: Created patch-release-${NEW_RELEASE} branch with customizations"

    # Show comparison URL
    comparison_url="https://github.com/open-policy-agent/gatekeeper/compare/release-${NEW_RELEASE}...stolostron:gatekeeper:release-${NEW_RELEASE}"
    info "Sanity check comparison: ${comparison_url}"
    confirm "Have you checked the comparison URL and verified the changes?"
}

# Phase 3: Interactive commit squashing and cleanup
phase3_squash_commits() {
    log "=== Phase 3: Interactive commit squashing and cleanup ==="

    info "Current commits on top of upstream:"
    execute "git log --oneline ${TAG}..HEAD"

    confirm "Ready to interactively rebase and squash commits? This will open your editor."

    # Interactive rebase to squash commits
    if [[ "${DRY_RUN}" == "false" ]]; then
        log "Starting interactive rebase..."
        git rebase -i "${TAG}"
    else
        log "Would execute: git rebase -i ${TAG}"
    fi

    # Clean up go modules
    log "Cleaning up Go modules..."
    execute "go mod tidy"
    execute "go mod vendor"

    # Add all changes and amend the commit
    execute "git add ."
    execute "git commit --amend --no-edit"

    success "Phase 3 completed: Commits squashed and cleaned up"
}

# Phase 4: Push patch branch and create PR
phase4_create_pr() {
    log "=== Phase 4: Push patch branch and create PR ==="

    confirm "Ready to push patch-release-${NEW_RELEASE} to ${FORK} and create PR?"

    # Push the patch branch
    execute "git push -u ${FORK} patch-release-${NEW_RELEASE}"

    # Create PR
    execute "gh pr create --repo stolostron/gatekeeper --fill --base \"release-${NEW_RELEASE}\""

    success "Phase 4 completed: PR created"
}

# Phase 5: Tag and push final release
phase5_tag_release() {
    log "=== Phase 5: Tag and push final release ==="

    echo -e "${YELLOW}Once the PR is approved and merged, run the following commands to tag and push the final release:${NC}"

    # Fetch latest commits from release branch
    echo "  git fetch ${STOLOSTRON} release-${NEW_RELEASE}"
    echo "  git checkout ${STOLOSTRON}/release-${NEW_RELEASE}"

    # Delete and recreate tag locally
    echo "  git tag --delete ${TAG} 2>/dev/null || true"
    echo "  git tag -a ${TAG} -m ${TAG}"

    # Push tag to stolostron
    echo "  git push ${STOLOSTRON} ${TAG}"
    echo -e "${YELLOW}To print these instructions again, use: --resume-from ${RESUME_FROM}${NC}"
}

# Main execution function
main() {
    log "Starting stolostron/gatekeeper release script"
    log "Command: ${0} $*"

    parse_args "$@"

    if [[ "${DRY_RUN}" == "true" ]]; then
        warning "DRY RUN MODE - No changes will be made"
    fi

    cd "${PROJECT_ROOT}"

    check_prerequisites
    detect_remotes
    get_latest_upstream_tag
    get_latest_stolostron_release
    setup_variables

    # Execute phases based on resume point
    if [[ ${RESUME_FROM} -le 1 ]]; then
        phase1_create_release_branch
        ((RESUME_FROM++))
    fi

    if [[ ${RESUME_FROM} -le 2 ]]; then
        phase2_create_patch_branch
        ((RESUME_FROM++))
    fi

    if [[ ${RESUME_FROM} -le 3 ]]; then
        phase3_squash_commits
        ((RESUME_FROM++))
    fi

    if [[ ${RESUME_FROM} -le 4 ]]; then
        phase4_create_pr
        ((RESUME_FROM++))
    fi

    if [[ ${RESUME_FROM} -le 5 ]]; then
        phase5_tag_release
    fi

    success "All requested phases completed successfully!"
    log "Log file: ${LOG_FILE}"
}

# Only run main if script is executed directly (not sourced)
if [[ "${BASH_SOURCE[0]}" == "${0}" ]]; then
    main "$@"
fi
